  bitmaps: OreSpriteBitmaps | null,
  ore: OreType,
  x: number,
  y: number,
): ImageBitmap | null {
  if (!bitmaps) return null
  const variants = bitmaps[ore]
  if (!variants || variants.length === 0) return null
  return variants[pickVariantIndexByPosition(x, y, variants.length)] ?? null
